template.css:
.card {
  background: transparent;
  border: none;
  border-radius: 0;
  padding: 0;
  box-shadow: none;
  overflow: visible;
}

.product01-card {
  display: flex;
  flex-direction: column;
  gap: 10px;
  color: #6B4F3A;
}

.product01-media {
  position: relative;
  width: 100%;
  aspect-ratio: 1 / 1;
  border-radius: 20px;
  overflow: hidden;
  border: 1px solid rgba(107, 79, 58, 0.1);
  background: #F8F6F1;
}

.product01-image {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  transition: transform 0.5s ease;
}

.product01-card:hover .product01-image {
  transform: scale(1.05);
}

.product01-action {
  position: absolute;
  right: 16px;
  bottom: 16px;
  width: 40px;
  height: 40px;
  border: none;
  border-radius: 9999px;
  background: #ffffff;
  color: var(--button-color, #6B4F3A);
  box-shadow: 0 8px 20px rgba(17, 24, 39, 0.12);
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  opacity: 0;
  transform: translateY(8px);
  transition: opacity 0.3s ease, transform 0.3s ease;
  font-size: var(--button-font-size, 16px);
  font-weight: var(--button-font-weight, 500);
  line-height: 1;
}

.product01-card:hover .product01-action {
  opacity: 1;
  transform: translateY(0);
}

.product01-meta {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 16px;
}

.product01-copy {
  min-width: 0;
  flex: 1;
}

.product01-title {
  margin: 0;
  font-size: var(--title-font-size, 16px);
  font-weight: var(--title-font-weight, 500);
  color: var(--title-color, #6B4F3A);
  line-height: var(--title-line-height, 1.4);
}

.product01-description {
  margin: 4px 0 0;
  font-size: var(--description-font-size, 12px);
  font-weight: var(--description-font-weight, 400);
  color: var(--description-color, #5A646A);
  line-height: var(--description-line-height, 1.5);
}

.product01-price {
  flex-shrink: 0;
  font-size: var(--price-font-size, 14px);
  font-weight: var(--price-font-weight, 600);
  color: var(--price-color, #6B4F3A);
  line-height: var(--price-line-height, 1.2);
}

.product01-badge {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  width: fit-content;
  padding: 4px 8px;
  border-radius: 6px;
  background: rgba(107, 79, 58, 0.1);
  color: var(--badge-color, #6B4F3A);
  font-size: var(--badge-font-size, 10px);
  font-weight: var(--badge-font-weight, 600);
  line-height: var(--badge-line-height, 1.2);
}

.product01-badge:empty {
  display: none;
}

[dir="rtl"] .product01-meta {
  flex-direction: row-reverse;
}

[dir="rtl"] .product01-action {
  right: auto;
  left: 16px;
}

@media (max-width: 640px) {
  .product01-action {
    opacity: 1;
    transform: translateY(0);
  }
}
